// Simple security validation
const body = $input.first().json.body;
const headers = $input.first().json.headers || {};

// Basic validation
if (!body || !body.message) {
  return {
    isValid: false,
    error: 'Invalid webhook payload'
  };
}

// Extract call data
const message = body.message;
return {
  isValid: true,
  callId: message.call?.id || `call_${Date.now()}`,
  transcript: message.transcript || '',
  callDuration: message.durationSeconds || 0,
  phoneNumber: message.call?.phoneNumber || '',
  endedReason: message.endedReason || '',
  cost: message.cost || 0,
  recordingUrl: message.recordingUrl || '',
  callDate: message.startedAt || new Date().toISOString(),
  rawData: message
};

// Parse the standardized JSON response
try {
  const aiResponse = $input.first().json.text;
  const standardizedData = JSON.parse(aiResponse);

  return {
    ...standardizedData,
    processing_status: 'success',
    ai_processed: true
  };
} catch (error) {
  // Fallback parsing if JSON is malformed
  const aiText = $input.first().json.text || '';

  return {
    record_id: $('Simple Validation').first().json.callId,
    customer_full_name: 'Parsing Error - Manual Review Required',
    processing_status: 'json_parse_error',
    ai_processed: false,
    raw_ai_response: aiText,
    error: error.message,
    requires_manager_review: true,
    created_at: new Date().toISOString()
  };
}

